detailed_optimizations.code_changes:
对 C4 矩阵的 p 维度进行分块，提高缓存利用率。

// 假设分块大小为 TILE_P
for (r = 0; r < _PB_NR; r++)
  for (q = 0; q < _PB_NQ; q++)
    for (p_outer = 0; p_outer < _PB_NP; p_outer += TILE_P) {
      int p_end = min(p_outer + TILE_P, _PB_NP);
      for (p = p_outer; p < p_end; p++)
        sum[p] = SCALAR_VAL(0.0);
      for (s = 0; s < _PB_NP; s++) {
        DATA_TYPE a_val = A[r][q][s];
        for (p = p_outer; p < p_end; p++)
          sum[p] += a_val * C4[s][p];
      }
      for (p = p_outer; p < p_end; p++)
        A[r][q][p] = sum[p];
    }

将 s 循环移到最外层，使 C4 矩阵按行访问连续。

for (r = 0; r < _PB_NR; r++)
  for (q = 0; q < _PB_NQ; q++) {
    for (p = 0; p < _PB_NP; p++)
      sum[p] = SCALAR_VAL(0.0);
    for (s = 0; s < _PB_NP; s++) {
      DATA_TYPE a_val = A[r][q][s];
      for (p = 0; p < _PB_NP; p++)
        sum[p] += a_val * C4[s][p];
    }
    for (p = 0; p < _PB_NP; p++)
      A[r][q][p] = sum[p];
  }

在计算当前迭代时预取下一次迭代需要的数据。

// 在 s 循环内添加预取指令
for (s = 0; s < _PB_NP; s++) {
  __builtin_prefetch(&C4[s+1][0], 0, 1); // 预取下一行 C4
  DATA_TYPE a_val = A[r][q][s];
  for (p = 0; p < _PB_NP; p++)
    sum[p] += a_val * C4[s][p];
}
